from sympy import isprime
def pell(n):
    if n == 0: return 0
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, 2*b + a
    return b
print([pell(k)**2 - 2 for k in range(1, 100)
       if (k % 2 == 1 or k == 2) and isprime(pell(k)**2 - 2)])

